import { useState, useEffect } from 'react'
import { useParams, useNavigate } from 'react-router-dom'
import Navbar from '../components/Navbar'
import Viewer360 from '../components/Viewer360'
import CameraMap3D from '../components/CameraMap3D'
import api from '../config/axios'
import toast from 'react-hot-toast'
import { ArrowLeft, Upload, Image as ImageIcon, Eye, Maximize2, Link2, Download, Trash2 } from 'lucide-react'
import './ProjectDetail.css'

const ProjectDetail = () => {
  const { id } = useParams()
  const navigate = useNavigate()
  const [project, setProject] = useState(null)
  const [photos, setPhotos] = useState([])
  const [loading, setLoading] = useState(true)
  const [uploading, setUploading] = useState(false)
  const [selectedPhoto, setSelectedPhoto] = useState(null)
  const [showViewer, setShowViewer] = useState(false)
  const [show3DMapFullscreen, setShow3DMapFullscreen] = useState(false)

  useEffect(() => {
    fetchProject()
    fetchPhotos()
  }, [id])

  const fetchProject = async () => {
    try {
      const response = await api.get(`/projects/${id}`)
      setProject(response.data)
    } catch (error) {
      console.error('Error fetching project:', error)
      toast.error('Error al cargar proyecto')
      navigate('/projects')
    } finally {
      setLoading(false)
    }
  }

  const fetchPhotos = async () => {
    try {
      const response = await api.get(`/projects/${id}/photos`)
      setPhotos(response.data)
    } catch (error) {
      console.error('Error fetching photos:', error)
    }
  }

  const handleFileUpload = async (e) => {
    const files = e.target.files
    if (!files || files.length === 0) return

    setUploading(true)

    const images = []
    const txtFiles = {}

    for (let i = 0; i < files.length; i++) {
      const file = files[i]
      const fileName = file.name
      const baseName = fileName.substring(0, fileName.lastIndexOf('.')) || fileName
      const extension = fileName.split('.').pop().toLowerCase()

      if (extension === 'txt') {
        txtFiles[baseName] = file
      } else if (['jpg', 'jpeg', 'png', 'gif'].includes(extension)) {
        images.push({ file, baseName })
      }
    }

    const uploadedPhotos = []
    
    for (const { file, baseName } of images) {
      const formData = new FormData()
      formData.append('file', file)
      formData.append('title', file.name)

      try {
        const response = await api.post(`/projects/${id}/photos/upload`, formData, {
          headers: {
            'Content-Type': 'multipart/form-data',
          },
        })
        
        toast.success(`Foto "${file.name}" subida`)
        
        uploadedPhotos.push({
          id: response.data.id,
          baseName: baseName
        })
        
      } catch (error) {
        console.error('Error uploading photo:', error)
        toast.error(`Error al subir "${file.name}"`)
      }
    }

    for (const photoData of uploadedPhotos) {
      if (txtFiles[photoData.baseName]) {
        const txtFormData = new FormData()
        txtFormData.append('file', txtFiles[photoData.baseName])
        
        try {
          await api.post(`/projects/${id}/photos/${photoData.id}/coordinates`, txtFormData, {
            headers: {
              'Content-Type': 'multipart/form-data',
            },
          })
          toast.success(`Coordenadas de "${photoData.baseName}" actualizadas`)
        } catch (error) {
          console.error('Error uploading coordinates:', error)
          toast.error(`Error al subir coordenadas de "${photoData.baseName}"`)
        }
      }
    }

    setUploading(false)
    await fetchPhotos()
  }

  const handlePhotoClick = (photo) => {
    setSelectedPhoto(photo)
    setShowViewer(true)
  }

  const handleNavigatePhoto = (photoId) => {
    const photo = photos.find(p => p.id === photoId)
    if (photo) {
      setSelectedPhoto(photo)
    }
  }

  const handleDeletePhoto = async (photoId, photoTitle) => {
    if (!confirm(`¿Estás seguro de eliminar "${photoTitle}"?`)) return

    try {
      await api.delete(`/projects/${id}/photos/${photoId}`)
      setPhotos(photos.filter(p => p.id !== photoId))
      toast.success('Foto eliminada')
    } catch (error) {
      console.error('Error deleting photo:', error)
      toast.error('Error al eliminar foto')
    }
  }

  const copyPhotoURL = (photo) => {
  const url = `${window.location.origin}/view/${photo.id}`
  navigator.clipboard.writeText(url)
  toast.success('URL copiada al portapapeles')
}

  const exportToCSV = () => {
    const photosWithCoords = photos.filter(p => p.latitude && p.longitude)
    
    if (photosWithCoords.length === 0) {
      toast.error('No hay fotos con coordenadas para exportar')
      return
    }

    let csv = 'Name,X,Y,Z,URL,Description\n'
    
    photosWithCoords.forEach(photo => {
      // INTERCAMBIADO: latitude (que era X) ahora es Y, longitude (que era Y) ahora es X
      const x = parseFloat(photo.longitude) || 0  // Ahora X = longitude
      const y = parseFloat(photo.latitude) || 0   // Ahora Y = latitude
      const zMatch = photo.description?.match(/z:([-\d.]+)/)
      const z = zMatch ? parseFloat(zMatch[1]) : 0
      const url = `${window.location.origin}/view/${photo.id}`
      
      csv += `"${photo.title}",${x},${y},${z},"${url}","360 Photo"\n`
    })

    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' })
    const link = document.createElement('a')
    const downloadUrl = URL.createObjectURL(blob)
    
    link.setAttribute('href', downloadUrl)
    link.setAttribute('download', `${project.name}_Coordenadas.csv`)
    link.style.visibility = 'hidden'
    document.body.appendChild(link)
    link.click()
    document.body.removeChild(link)
    
    toast.success('Archivo CSV exportado para Revit')
  }

  const photosWithCoords = photos.filter(p => p.latitude && p.longitude)

  if (loading) {
    return (
      <div className="page">
        <Navbar />
        <div className="loading">Cargando proyecto...</div>
      </div>
    )
  }

  return (
    <div className="page">
      <Navbar />
      
      <div className="container project-detail-content">
        <button className="btn-back" onClick={() => navigate('/projects')}>
          <ArrowLeft size={20} />
          Volver a proyectos
        </button>

        <div className="project-detail-header">
          <div>
            <h1>{project?.name}</h1>
            {project?.description && <p className="project-desc">{project.description}</p>}
            {project?.location && <p className="project-loc">📍 {project.location}</p>}
          </div>

          <div className="project-actions">
            {photosWithCoords.length > 0 && (
              <button className="btn btn-secondary" onClick={exportToCSV}>
                <Download size={20} />
                Exportar CSV
              </button>
            )}
            
            <label className="btn btn-primary upload-btn">
              <Upload size={20} />
              {uploading ? 'Subiendo...' : 'Subir Fotos + TXT'}
              <input
                type="file"
                multiple
                accept="image/*,.txt"
                onChange={handleFileUpload}
                disabled={uploading}
                style={{ display: 'none' }}
              />
            </label>
          </div>
        </div>

        {photosWithCoords.length > 0 && (
          <div className="viewer-3d-section">
            <div className="viewer-3d-header">
              <h2>Vista 3D - Navegación por Coordenadas</h2>
              <button 
                className="btn-expand"
                onClick={() => setShow3DMapFullscreen(true)}
                title="Ver en pantalla completa"
              >
                <Maximize2 size={20} />
                <span>Expandir</span>
              </button>
            </div>
            <div className="viewer-3d-container">
              <CameraMap3D
                photos={photos}
                onPhotoClick={handlePhotoClick}
                activePhotoId={selectedPhoto?.id}
                embedded={true}
              />
            </div>
          </div>
        )}

        <div className="photos-section">
          <h2>Fotos 360° del Proyecto ({photos.length})</h2>
          
          {photos.length > 0 ? (
            <div className="photos-grid">
              {photos.map(photo => (
                <div key={photo.id} className="photo-card">
                  <button
                    className="btn-delete-photo"
                    onClick={(e) => {
                      e.stopPropagation()
                      handleDeletePhoto(photo.id, photo.title)
                    }}
                    title="Eliminar foto"
                  >
                    <Trash2 size={18} />
                  </button>
                  
                  <div className="photo-image-container" onClick={() => handlePhotoClick(photo)}>
                    <img 
                      src={photo.url.startsWith('http') ? photo.url : `http://localhost:8001${photo.url}`}
                      alt={photo.title}
                      className="photo-image"
                    />
                    <div className="photo-overlay">
                      <Eye size={32} />
                      <span>Ver en 360°</span>
                    </div>
                  </div>
                  <div className="photo-info">
                    <h4>{photo.title}</h4>
                    {photo.latitude && photo.longitude && (
                      <span className="photo-coords">
                        📍 X:{photo.longitude}, Y:{photo.latitude}
                      </span>
                    )}
                    <button 
                      className="btn-copy-url"
                      onClick={() => copyPhotoURL(photo)}
                      title="Copiar URL de esta foto"
                    >
                      <Link2 size={16} />
                      Copiar URL
                    </button>
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <div className="empty-photos">
              <ImageIcon size={64} color="#cbd5e0" />
              <h3>No hay fotos aún</h3>
              <p>Sube la primera foto de este proyecto</p>
              <label className="btn btn-primary">
                <Upload size={20} />
                Subir Primera Foto
                <input
                  type="file"
                  multiple
                  accept="image/*,.txt"
                  onChange={handleFileUpload}
                  style={{ display: 'none' }}
                />
              </label>
            </div>
          )}
        </div>
      </div>

      {showViewer && selectedPhoto && (
        <Viewer360
          photo={selectedPhoto}
          photos={photos}
          onClose={() => setShowViewer(false)}
          onNavigate={handleNavigatePhoto}
        />
      )}

      {show3DMapFullscreen && (
        <CameraMap3D
          photos={photos}
          onPhotoClick={handlePhotoClick}
          activePhotoId={selectedPhoto?.id}
          onClose={() => setShow3DMapFullscreen(false)}
        />
      )}
    </div>
  )
}

export default ProjectDetail
